============ 补偿红包和蚕豆

SELECT sum(if(cate2_type=4,add_candou_num/100,0)) AS add_candou -- 补偿蚕豆
   FROM dwd.dwd_sr_callcenter_workorder
   WHERE dt BETWEEN '2025-05-20' AND '2025-05-29'
     AND length(order_id)>=10 -- 排除空值订单
;


-- 工单红包
SELECT sum(redpacket_amt)
   FROM dwd.dwd_sr_callcenter_workorder_rp_grant
   WHERE date_format(create_time,'%Y-%m-%d') BETWEEN '2025-05-20' AND '2025-05-29'
     AND redpacket_type=1 -- 霸王餐
     AND status=1 -- 发放成功
 ;



-- 红包使用
DROP VIEW IF EXISTS used_rp_info;


CREATE VIEW IF NOT EXISTS used_rp_info (auto_id,order_id,real_rebate_amt) AS
  (SELECT auto_id,
          order_id,
          real_rebate_amt
   FROM dwd.dwd_sr_market_redpack_use_record
   WHERE date_format(dt,'%Y-%m-%d') BETWEEN date_sub(current_date(),interval 210 DAY) AND date_sub(current_date(),interval 1 DAY)
     AND redpacket_use_status = 2 -- 已使用
);

select
  sum(real_rebate_amt) used_rp_amt
from 
(SELECT record_id
   FROM dwd.dwd_sr_callcenter_workorder_rp_grant
   WHERE date_format(create_time,'%Y-%m-%d') BETWEEN '2025-05-20' AND '2025-05-29'
     AND redpacket_type=1 -- 霸王餐
     AND status=1 -- 发放成功
   GROUP BY 1) a
inner join used_rp_info b on a.record_id=b.auto_id;

==============补偿前后用户复购
DROP VIEW IF EXISTS workorder_info;


CREATE VIEW IF NOT EXISTS workorder_info (dt,work_order_id,order_id, cate2_type, cate3_type, add_candou_num,user_id) AS
  (SELECT dt,work_order_id,
          order_id,
          cate2_type,
          cate3_type,
          add_candou_num,
          user_id
   FROM dwd.dwd_sr_callcenter_workorder
   WHERE dt BETWEEN '2025-05-20' AND '2025-05-29'
     AND length(order_id)>=10 -- 排除空值订单
     AND is_user_liability=1 -- 用户责任

   GROUP BY 1,
            2,
            3,
            4,
            5,
            6,
            7);


-- 工单红包
DROP VIEW IF EXISTS rp_info;


CREATE VIEW IF NOT EXISTS rp_info (dat,record_id,work_order_id,redpacket_amt) AS
  (SELECT date_format(create_time,'%Y-%m-%d') as dat,record_id,work_order_id,redpacket_amt
   FROM dwd.dwd_sr_callcenter_workorder_rp_grant
   WHERE date_format(create_time,'%Y-%m-%d') BETWEEN '2025-05-20' AND '2025-05-29'
     AND redpacket_type=1 -- 霸王餐
     AND status=1 -- 发放成功
   GROUP BY 1,2,3,4);


-- 补偿用户
DROP VIEW IF EXISTS user_info;


CREATE VIEW IF NOT EXISTS user_info (user_id) AS (
  select
    a.user_id
  from workorder_info a left join rp_info b on a.work_order_id=b.work_order_id
  where (a.cate2_type=4 or b.work_order_id IS NOT NULL) and ((a.dt between '2025-05-21' and '2025-05-22') or (b.dat between '2025-05-21' and '2025-05-22'))
  group by 1
)


