-- 补偿后复购
select
  `用户价值类型`,
  count(distinct a.`用户ID`) `进线用户量`,
  count(distinct if(b.user_id is not null,a.`用户ID`,null)) `7日内复购用户量`
from (
SELECT 
       a.user_id `用户ID`,
       CASE
           WHEN b.user_true_level=0 THEN '低价值用户'
           WHEN b.user_true_level=1 THEN '普通价值用户'
           WHEN b.user_true_level=2 THEN '高价值用户'
           WHEN b.user_true_level=3 THEN '超高价值用户'
       END `用户价值类型`
FROM
     user_info a
-- 用户价值
LEFT JOIN dwd.dwd_sr_user_usertag_dm_02 b ON a.user_id=b.user_id
group by 1,2) a
left join (select user_id from dwd.dwd_sr_order_promotion_order where dt between '2025-05-23' and '2025-05-29' and order_status in (2,8) group by 1) b on a.`用户ID`=b.user_id
where a.`用户价值类型`<>'低价值用户'
group by 1;










